/**
 * Publication Overview — PDF Export + Styling plug-in for WoodWing Studio
 *
 * Adds to the Publication Overview (triple-dot menu, top right):
 *  - "Export PDF…": merge the per-page print PDFs Studio Server already stores
 *    ('output' renditions, falling back to JPG page previews) into a single
 *    downloadable PDF — entire issue, a page range, filtered by workflow
 *    status and/or edition.
 *  - Styling: "sent to press" badge on page tiles, a diagonal watermark over
 *    press-status thumbnails, status color accents, late (past hard deadline)
 *    and approaching (past soft deadline) highlights, and a density control.
 *    Pure CSS/DOM decoration, fully reversible, self-disables if the Studio DOM
 *    changes. (Watermark and deadline looks are editable CSS blocks in
 *    src/70-styling-engine.js.)
 *
 * Runs inside the Publication Overview child application (same-origin iframe)
 * where the PoUiSdk and the relayed ContentStationSdk globals are available.
 *
 * GENERATED FILE NOTICE: dist/pub-overview-plugin.js is generated by
 * build-plugin.js from the files in src/ — edit those and rebuild.
 *
 * Registration (WoodWing Cloud): Management Console → Integrations →
 * Plug-ins → Publication Overview → Add new → URL of the dist file.
 */
(function () {
  'use strict';

  var VERSION = '0.3.0';
  var TAG = '[pub-pdf]';

  if (typeof PoUiSdk === 'undefined') {
    // Not in a Publication Overview context (or loaded in the wrong plugin
    // slot in the Management Console) — do nothing, never break the page.
    console.warn(TAG + ' PoUiSdk not available — plug-in not loaded in a Publication Overview context.');
    return;
  }

  // ─── Defaults (user-tunable via the settings section of the dialog) ───────
  var DEFAULT_SETTINGS = {
    // Workflow status names that mean "this page is done / sent to press".
    // Matched case-insensitively against the layout's status name.
    pressStatusNames: ['Complete', 'Sent to press', 'Ready for Press'],
    // Text shown on the badge overlay of pages in a press status.
    badgeLabel: 'PRESS',
    badgeEnabled: true,
    // Diagonal watermark stamped across the thumbnail of pages in a press
    // status (uses the same pressStatusNames list). Toggle off to hide it.
    watermarkEnabled: true,
    watermarkText: 'SENT TO PRESS',
    // Colored status accent bar on every page tile (uses the official
    // workflow status color).
    accentsEnabled: true,
    // Pulsing red outline on non-press pages whose hard deadline (Deadline)
    // has passed — "late".
    overdueEnabled: true,
    // Amber outline on non-press pages whose soft deadline (DeadlineSoft) has
    // passed but hard deadline has not — "approaching".
    dueSoonEnabled: true,
    // Page grid density: 'normal' leaves Studio untouched.
    density: 'normal', // 'compact' | 'normal' | 'large'
    // Rendition engine. 'client' merges stored renditions in the browser.
    // 'ids' is reserved for the v2 InDesign Server backend (see
    // IdsRenditionSource) and is not selectable yet.
    engine: 'client',
    // Prefer 'output' (print PDF) renditions; when false, always use JPG
    // previews (debug aid, reachable via window.__pubPdfDebug).
    preferOutput: true,
  };

  var DENSITY_ZOOM = { compact: 0.7, normal: 1, large: 1.35 };

  // ─── Studio Server API (same origin — cookie session) ─────────────────────
  // Studio uses cookie-based sessions on current Studio Server versions:
  // requests authenticate via the session cookie plus the
  // X-WoodWing-Application header (CSRF guard), with Ticket set to null in
  // the payload. On older ticket-based setups getInfo().Ticket is populated
  // and used instead. (Same pattern as the word-digital-article-builder
  // plug-in, proven on this server.)
  var WW_APP = 'Content Station';
  var WW_APP_HEADER = { 'X-WoodWing-Application': WW_APP };

  function getTicket() {
    try {
      var info = ContentStationSdk.getInfo();
      return (info && info.Ticket) || '';
    } catch (e) { return ''; }
  }

  function serverIndexUrl() {
    // The PO iframe lives at /app/publicationoverview/, so a host-absolute
    // path is the safe default; csConfig is used when exposed in this frame.
    var rel = (window.csConfig && window.csConfig.serverUrl) || '/server/index.php';
    return new URL(rel, window.location.href).href;
  }

  function callServer(method, params) {
    params = params || {};
    if (!('Ticket' in params) || !params.Ticket) params.Ticket = getTicket() || null;
    return fetch(serverIndexUrl() + '?protocol=JSON&method=' + encodeURIComponent(method), {
      method: 'POST',
      credentials: 'same-origin',
      headers: Object.assign({ 'Content-Type': 'application/json' }, WW_APP_HEADER),
      body: JSON.stringify({ method: method, id: '1', params: [params], jsonrpc: '2.0' }),
    }).then(function (r) {
      if (!r.ok) throw new Error(method + ' failed: HTTP ' + r.status);
      return r.json();
    }).then(function (j) {
      if (j.error) {
        console.error(TAG + ' ' + method + ' error response:', j.error);
        var e = j.error;
        var parts = [];
        if (e.message) parts.push(e.message);
        if (e.data && e.data.detail && e.data.detail !== e.message) parts.push(e.data.detail);
        if (e.code) parts.push('(code ' + e.code + ')');
        throw new Error(method + ' failed: ' + (parts.join(' — ') || JSON.stringify(e)));
      }
      return j.result;
    });
  }

  // Download a rendition file. FileUrls from GetPages point at the Transfer
  // Server and return HTTP 400 ("Please specify ticket param") unless the
  // ww-app parameter is present, which makes the session cookie apply —
  // verified against this server.
  function fetchBinary(url) {
    if (url.indexOf('ww-app=') === -1) {
      url += (url.indexOf('?') >= 0 ? '&' : '?') + 'ww-app=' + encodeURIComponent(WW_APP);
    }
    return fetch(url, { credentials: 'same-origin' }).then(function (r) {
      if (!r.ok) throw new Error('Rendition download failed: HTTP ' + r.status);
      return r.arrayBuffer();
    });
  }

  function notify(content, type) {
    try {
      ContentStationSdk.showNotification({ content: content, type: type || 'default', timeout: 6000, showX: true });
    } catch (e) {
      console.info(TAG + ' ' + content);
    }
  }

  // ─── Issue data layer ──────────────────────────────────────────────────────
  // One GetPagesInfo call is the source of truth: it is the same service the
  // Publication Overview itself renders from, and carries both the page grid
  // (PageObjects) and the layout workflow states (LayoutObjects).

  function currentFilter() {
    try { return PoUiSdk.currentFilterSetting() || {}; } catch (e) { return {}; }
  }

  function loadIssueModel(issueId, editionId) {
    return callServer('GetPagesInfo', {
      Issue: { Id: String(issueId), __classname__: 'Issue' },
      IDs: null,
      Edition: editionId ? { Id: String(editionId), __classname__: 'Edition' } : null,
      Category: null,
      State: null,
    }).then(function (r) {
      var model = {
        issueId: String(issueId),
        editionId: editionId ? String(editionId) : null,
        brandName: '',
        issueName: '',
        expectedPages: r.ExpectedPages,
        layouts: {},
        pages: [],
        states: [],
      };

      var los = r.LayoutObjects || [];
      var statesSeen = {};
      for (var i = 0; i < los.length; i++) {
        var lo = los[i];
        var st = lo.State || {};
        model.layouts[String(lo.Id)] = {
          id: String(lo.Id),
          name: lo.Name,
          stateId: st.Id ? String(st.Id) : '',
          stateName: st.Name || '',
          stateColor: st.Color ? ('#' + String(st.Color).replace(/^#/, '')) : '',
          lockedBy: lo.LockedBy || '',
          deadline: null,     // hard deadline, filled by loadDeadlines()
          deadlineSoft: null, // soft/warning deadline, filled by loadDeadlines()
        };
        if (st.Id && !statesSeen[st.Id]) {
          statesSeen[st.Id] = true;
          model.states.push({ id: String(st.Id), name: st.Name || '', color: st.Color ? '#' + st.Color : '' });
        }
        if (!model.brandName && lo.Publication && lo.Publication.Name) model.brandName = lo.Publication.Name;
        if (!model.issueName && lo.Target && lo.Target.Issue && lo.Target.Issue.Name) model.issueName = lo.Target.Issue.Name;
      }

      var eps = r.EditionsPages || [];
      for (var e = 0; e < eps.length; e++) {
        var pos = eps[e].PageObjects || [];
        for (var p = 0; p < pos.length; p++) {
          var po = pos[p];
          model.pages.push({
            layoutId: String(po.ParentLayoutId),
            pageNumber: String(po.PageNumber),
            pageOrder: Number(po.PageOrder),
            pageSequence: Number(po.PageSequence),
            width: Number(po.Width),
            height: Number(po.Height),
            outputAvailable: !!po.OutputRenditionAvailable,
          });
        }
      }
      model.pages.sort(function (a, b) { return a.pageOrder - b.pageOrder || a.pageSequence - b.pageSequence; });
      return model;
    });
  }

  // Deadlines are not part of GetPagesInfo's LayoutObjects; fetch them
  // separately and tolerate failure (styling then simply skips deadline marks).
  // Deadline = hard deadline ("late"); DeadlineSoft = soft/warning deadline
  // ("approaching").
  function loadDeadlines(model) {
    return callServer('QueryObjects', {
      FirstEntry: 1, MaxEntries: 500, Hierarchical: false,
      Params: [
        { Property: 'Type', Operation: '=', Value: 'Layout', __classname__: 'QueryParam' },
        { Property: 'IssueId', Operation: '=', Value: String(model.issueId), __classname__: 'QueryParam' },
      ],
      MinimalProps: ['ID', 'Deadline', 'DeadlineSoft'],
    }).then(function (r) {
      var cols = (r.Columns || []).map(function (c) { return c.Name; });
      var idIdx = cols.indexOf('ID'), dlIdx = cols.indexOf('Deadline'), softIdx = cols.indexOf('DeadlineSoft');
      (r.Rows || []).forEach(function (row) {
        var lay = model.layouts[String(row[idIdx])];
        if (!lay) return;
        if (dlIdx >= 0 && row[dlIdx]) lay.deadline = row[dlIdx];
        if (softIdx >= 0 && row[softIdx]) lay.deadlineSoft = row[softIdx];
      });
      return model;
    }).catch(function (e) {
      console.warn(TAG + ' deadlines unavailable: ' + e.message);
      return model;
    });
  }

  // Brand name, issue name and the issue channel's editions — for the
  // dialog's edition selector and the download filename. GetPagesInfo's
  // LayoutObjects do not carry these names, so resolve them here. Note that
  // GetPublications ignores PublicationIds and returns every brand, so match
  // on the brand id explicitly. Falls back to empty fields on any surprise.
  function loadIssueMeta(brandId, issueId) {
    var empty = { brandName: '', issueName: '', editions: [] };
    return callServer('GetPublications', {
      PublicationIds: [String(brandId)],
      RequestInfo: ['PubChannels', 'Issues', 'Editions'],
    }).then(function (r) {
      var infos = (r && r.Publications) || [];
      for (var i = 0; i < infos.length; i++) {
        if (String(infos[i].Id) !== String(brandId)) continue;
        var chans = infos[i].PubChannels || [];
        for (var c = 0; c < chans.length; c++) {
          var issues = chans[c].Issues || [];
          for (var s = 0; s < issues.length; s++) {
            if (String(issues[s].Id) === String(issueId)) {
              return {
                brandName: infos[i].Name || '',
                issueName: issues[s].Name || '',
                editions: (chans[c].Editions || []).map(function (ed) {
                  return { id: String(ed.Id), name: ed.Name };
                }),
              };
            }
          }
        }
      }
      return empty;
    }).catch(function (e) {
      console.warn(TAG + ' issue meta unavailable: ' + e.message);
      return empty;
    });
  }

  // Parse a page range string like "1-5, 9, 12-14" against the model's
  // pages. Tokens match the visible page number first, then the page order.
  function filterPagesByRange(pages, rangeText) {
    var wanted = {};
    var tokens = String(rangeText).split(',');
    for (var i = 0; i < tokens.length; i++) {
      var t = tokens[i].trim();
      if (!t) continue;
      var m = t.match(/^(\d+)\s*-\s*(\d+)$/);
      if (m) {
        var lo = parseInt(m[1], 10), hi = parseInt(m[2], 10);
        if (hi < lo) { var tmp = lo; lo = hi; hi = tmp; }
        for (var n = lo; n <= hi; n++) wanted[n] = true;
      } else if (/^\d+$/.test(t)) {
        wanted[parseInt(t, 10)] = true;
      } else {
        throw new Error('Invalid page range: "' + t + '"');
      }
    }
    return pages.filter(function (p) {
      return wanted[parseInt(p.pageNumber, 10)] || wanted[p.pageOrder];
    });
  }

  // ─── Rendition sources ─────────────────────────────────────────────────────
  // A rendition source resolves a page of the issue to printable bytes:
  //   prime(layoutIds)        → Promise, fetches/caches file pointers
  //   getPagePdf(page)        → Promise<{ kind: 'pdf'|'jpeg', bytes: ArrayBuffer }>
  // This interface is the seam for the v2 high-quality backend: swap the
  // client source for one that queues InDesign Server jobs without touching
  // the PDF engine or the dialog.

  function ClientRenditionSource(issueId, editionId, preferOutput) {
    // key: layoutId + '|' + pageSequence → { output: url, preview: url }
    var files = {};

    function prime(layoutIds) {
      var chunks = [];
      for (var i = 0; i < layoutIds.length; i += 5) chunks.push(layoutIds.slice(i, i + 5));
      return chunks.reduce(function (p, chunk) {
        return p.then(function () {
          return callServer('GetPages', {
            Issue: { Id: String(issueId), __classname__: 'Issue' },
            IDs: chunk,
            Edition: editionId ? { Id: String(editionId), __classname__: 'Edition' } : null,
            Renditions: ['output', 'preview'],
            RequestMetaData: true,
            RequestFiles: true,
          }).then(function (r) {
            var infos = r.ObjectPageInfos || [];
            for (var oi = 0; oi < infos.length; oi++) {
              var md = infos[oi].MetaData;
              var layoutId = md && md.BasicMetaData ? String(md.BasicMetaData.ID) : null;
              var pages = infos[oi].Pages || [];
              for (var pi = 0; pi < pages.length; pi++) {
                var pg = pages[pi];
                var key = (layoutId || '?') + '|' + Number(pg.PageSequence);
                var rec = files[key] || (files[key] = {});
                var fs = pg.Files || [];
                for (var fi = 0; fi < fs.length; fi++) {
                  var f = fs[fi];
                  if (f.Rendition === 'output' && f.FileUrl) rec.output = f.FileUrl;
                  if (f.Rendition === 'preview' && f.FileUrl) rec.preview = f.FileUrl;
                }
              }
            }
          });
        });
      }, Promise.resolve());
    }

    function getPagePdf(page) {
      var rec = files[page.layoutId + '|' + page.pageSequence] || {};
      var useOutput = preferOutput && rec.output;
      var url = useOutput ? rec.output : rec.preview;
      if (!url) {
        return Promise.reject(new Error('No rendition stored for page ' + page.pageNumber +
          ' (save the layout in InDesign to generate page previews)'));
      }
      return fetchBinary(url).then(function (bytes) {
        return { kind: useOutput ? 'pdf' : 'jpeg', bytes: bytes };
      });
    }

    return { prime: prime, getPagePdf: getPagePdf, kindHint: function (page) {
      var rec = files[page.layoutId + '|' + page.pageSequence] || {};
      return (preferOutput && rec.output) ? 'pdf' : (rec.preview ? 'jpeg' : 'none');
    } };
  }

  // v2 seam — high-quality export via InDesign Server.
  // Contract for the future implementation:
  //  - prime(layoutIds) queues an IDS export job (e.g. via a Studio Server
  //    plug-in endpoint or CreateObjectOperations) for the selected layouts
  //    and polls until the job completes.
  //  - getPagePdf(page) resolves per-page PDFs from the job result. A job
  //    may return one multi-page PDF per layout plus a page map; in that
  //    case getPagePdf slices by the page's sequence within the layout.
  // Selecting engine 'ids' in settings is blocked until this exists.
  function IdsRenditionSource() {
    return {
      prime: function () {
        return Promise.reject(new Error('High-quality InDesign Server export is not implemented yet (v2).'));
      },
      getPagePdf: function () {
        return Promise.reject(new Error('High-quality InDesign Server export is not implemented yet (v2).'));
      },
      kindHint: function () { return 'none'; },
    };
  }

  function createRenditionSource(settings, issueId, editionId) {
    if (settings.engine === 'ids') return IdsRenditionSource();
    return ClientRenditionSource(issueId, editionId, settings.preferOutput !== false);
  }

  // ─── PDF engine ────────────────────────────────────────────────────────────
  // pdf-lib is loaded on demand and kept plugin-local per the SDK guidance on
  // managing external dependencies.
  var pdfLibPromise = null;
  function loadPdfLib() {
    if (window.PDFLib) return Promise.resolve(window.PDFLib);
    if (!pdfLibPromise) {
      pdfLibPromise = new Promise(function (resolve, reject) {
        var s = document.createElement('script');
        s.src = 'https://cdn.jsdelivr.net/npm/pdf-lib@1.17.1/dist/pdf-lib.min.js';
        s.onload = function () { resolve(window.PDFLib); };
        s.onerror = function () {
          pdfLibPromise = null;
          reject(new Error('Could not load the PDF library (pdf-lib). Check that cdn.jsdelivr.net is reachable.'));
        };
        document.head.appendChild(s);
      });
    }
    return pdfLibPromise;
  }

  // Merge the given pages (in order) into one PDF and return its bytes.
  // Pages are processed sequentially: bounded memory use and honest progress.
  // hooks: { onProgress(done, total, page), isCancelled(), onPageSkipped(page, err) }
  function exportPdf(pages, source, hooks) {
    return loadPdfLib().then(function (PDFLib) {
      return PDFLib.PDFDocument.create().then(function (doc) {
        var skipped = [];
        var chain = Promise.resolve();
        pages.forEach(function (page, i) {
          chain = chain.then(function () {
            if (hooks.isCancelled && hooks.isCancelled()) throw new Error('__cancelled__');
            return source.getPagePdf(page).then(function (res) {
              if (res.kind === 'pdf') {
                return PDFLib.PDFDocument.load(res.bytes, { ignoreEncryption: true }).then(function (src) {
                  // Per-page 'output' renditions are single-page PDFs; if a
                  // multi-page file shows up, take the page matching this
                  // page's sequence within its layout.
                  var idx = Math.min(Math.max(page.pageSequence - 1, 0), src.getPageCount() - 1);
                  return doc.copyPages(src, [idx]).then(function (copied) { doc.addPage(copied[0]); });
                });
              }
              // JPG preview → full-bleed image on a page of the true page size.
              return doc.embedJpg(res.bytes).then(function (img) {
                var pg = doc.addPage([page.width, page.height]);
                pg.drawImage(img, { x: 0, y: 0, width: page.width, height: page.height });
              });
            }).catch(function (err) {
              if (err && err.message === '__cancelled__') throw err;
              console.warn(TAG + ' page ' + page.pageNumber + ' skipped: ' + err.message);
              skipped.push({ page: page, error: err });
              if (hooks.onPageSkipped) hooks.onPageSkipped(page, err);
            }).then(function () {
              if (hooks.onProgress) hooks.onProgress(i + 1, pages.length, page);
            });
          });
        });
        return chain.then(function () {
          if (doc.getPageCount() === 0) throw new Error('No pages could be exported — no stored renditions found.');
          return doc.save().then(function (bytes) {
            return { bytes: bytes, skipped: skipped, pageCount: doc.getPageCount() };
          });
        });
      });
    });
  }

  function sanitizeFilename(name) {
    return String(name).replace(/[\/\\:*?"<>|]+/g, '-').replace(/\s+/g, ' ').trim();
  }

  function buildFilename(model, suffixes) {
    var base = (model.brandName || 'Issue') + ' - ' + (model.issueName || model.issueId);
    var extra = (suffixes || []).filter(Boolean).map(function (s) { return ' (' + s + ')'; }).join('');
    return sanitizeFilename(base + extra) + '.pdf';
  }

  function downloadBlob(bytes, filename) {
    var blob = new Blob([bytes], { type: 'application/pdf' });
    var url = URL.createObjectURL(blob);
    var a = document.createElement('a');
    a.href = url;
    a.download = filename;
    document.body.appendChild(a);
    a.click();
    setTimeout(function () {
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
    }, 1500);
  }

  // ─── Export dialog ─────────────────────────────────────────────────────────
  // Self-contained overlay in the PO iframe document (full DOM control, no
  // cross-frame modal quirks). Styles live in one injected block, all rules
  // scoped under .ppx-dialog-overlay.

  var DIALOG_CSS =
    '.ppx-dialog-overlay{position:fixed;inset:0;background:rgba(0,0,0,.45);z-index:99990;display:flex;align-items:center;justify-content:center;font-family:inherit}' +
    '.ppx-dialog{background:#fff;color:#333;border-radius:6px;box-shadow:0 8px 40px rgba(0,0,0,.35);width:460px;max-width:92vw;max-height:90vh;overflow:auto;padding:0}' +
    '.ppx-dialog h2{font-size:16px;font-weight:600;margin:0;padding:14px 18px;border-bottom:1px solid #e5e5e5}' +
    '.ppx-dialog .ppx-body{padding:14px 18px}' +
    '.ppx-dialog .ppx-ctx{color:#777;font-size:12px;margin:0 0 12px}' +
    '.ppx-dialog fieldset{border:1px solid #e5e5e5;border-radius:4px;margin:0 0 12px;padding:8px 12px}' +
    '.ppx-dialog legend{font-size:11px;text-transform:uppercase;letter-spacing:.05em;color:#999;padding:0 4px}' +
    '.ppx-dialog label{display:flex;align-items:center;gap:7px;font-size:13px;padding:3px 0;cursor:pointer}' +
    '.ppx-dialog input[type=text]{width:130px;padding:3px 6px;border:1px solid #ccc;border-radius:3px;font-size:13px}' +
    '.ppx-dialog select{padding:3px 6px;border:1px solid #ccc;border-radius:3px;font-size:13px}' +
    '.ppx-state-dot{display:inline-block;width:10px;height:10px;border-radius:50%;border:1px solid rgba(0,0,0,.2)}' +
    '.ppx-note{font-size:12px;color:#777;margin:2px 0 0}' +
    '.ppx-error{color:#c0392b;font-size:12px;margin:8px 0 0;white-space:pre-wrap}' +
    '.ppx-progress{display:none;margin:10px 0 0}' +
    '.ppx-progress-bar{height:6px;background:#eee;border-radius:3px;overflow:hidden}' +
    '.ppx-progress-fill{height:100%;width:0;background:#f5a623;transition:width .2s}' +
    '.ppx-progress-text{font-size:12px;color:#777;margin-top:4px}' +
    '.ppx-actions{display:flex;justify-content:space-between;align-items:center;gap:8px;padding:12px 18px;border-top:1px solid #e5e5e5}' +
    '.ppx-actions .ppx-right{display:flex;gap:8px}' +
    '.ppx-btn{border:1px solid #ccc;background:#fff;color:#333;border-radius:4px;padding:6px 14px;font-size:13px;cursor:pointer}' +
    '.ppx-btn-primary{background:#f5a623;border-color:#f5a623;color:#fff;font-weight:600}' +
    '.ppx-btn:disabled{opacity:.5;cursor:default}' +
    '.ppx-gear{background:none;border:none;font-size:15px;cursor:pointer;color:#999;padding:2px 6px}' +
    '.ppx-settings{display:none;border-top:1px dashed #e5e5e5;margin-top:10px;padding-top:10px}' +
    '.ppx-settings.ppx-open{display:block}' +
    '.ppx-settings input[type=text]{width:100%}';

  function ensureDialogStyles() {
    if (!document.getElementById('ppx-dialog-styles')) {
      var st = document.createElement('style');
      st.id = 'ppx-dialog-styles';
      st.textContent = DIALOG_CSS;
      document.head.appendChild(st);
    }
  }

  function el(tag, attrs, children) {
    var node = document.createElement(tag);
    Object.keys(attrs || {}).forEach(function (k) {
      if (k === 'text') node.textContent = attrs[k];
      else if (k.slice(0, 2) === 'on') node.addEventListener(k.slice(2), attrs[k]);
      else node.setAttribute(k, attrs[k]);
    });
    (children || []).forEach(function (c) { if (c) node.appendChild(c); });
    return node;
  }

  function openExportDialog() {
    var filter = currentFilter();
    if (!filter.issueId) {
      notify('Could not determine the current issue — open the Publication Overview on an issue first.', 'error');
      return;
    }
    ensureDialogStyles();

    var state = {
      model: null,
      meta: null,
      editions: [],
      cancelled: false,
      exporting: false,
    };

    // ── skeleton ──
    var ctxLine = el('p', { class: 'ppx-ctx', text: 'Loading issue…' });
    var errLine = el('div', { class: 'ppx-error' });
    var rangeInput = el('input', { type: 'text', placeholder: 'e.g. 1-5, 9', disabled: '' });
    var scopeIssue = el('input', { type: 'radio', name: 'ppx-scope', checked: '' });
    var scopeRange = el('input', { type: 'radio', name: 'ppx-scope' });
    scopeIssue.addEventListener('change', function () { rangeInput.disabled = true; });
    scopeRange.addEventListener('change', function () { rangeInput.disabled = false; rangeInput.focus(); });
    rangeInput.addEventListener('focus', function () { scopeRange.checked = true; rangeInput.disabled = false; });

    var statusBox = el('div');
    var editionSelect = el('select');
    var renditionNote = el('p', { class: 'ppx-note', text: '' });

    var progressFill = el('div', { class: 'ppx-progress-fill' });
    var progressText = el('div', { class: 'ppx-progress-text', text: '' });
    var progressWrap = el('div', { class: 'ppx-progress' }, [
      el('div', { class: 'ppx-progress-bar' }, [progressFill]),
      progressText,
    ]);

    var exportBtn = el('button', { class: 'ppx-btn ppx-btn-primary', text: 'Export PDF', disabled: '' });
    var cancelBtn = el('button', { class: 'ppx-btn', text: 'Close' });

    // ── settings section (gear) ──
    var settings = loadSettings();
    var pressInput = el('input', { type: 'text', value: settings.pressStatusNames.join(', ') });
    var badgeChk = el('input', { type: 'checkbox' }); badgeChk.checked = settings.badgeEnabled;
    var watermarkChk = el('input', { type: 'checkbox' }); watermarkChk.checked = settings.watermarkEnabled;
    var watermarkInput = el('input', { type: 'text', value: settings.watermarkText || '' });
    var accentChk = el('input', { type: 'checkbox' }); accentChk.checked = settings.accentsEnabled;
    var overdueChk = el('input', { type: 'checkbox' }); overdueChk.checked = settings.overdueEnabled;
    var dueSoonChk = el('input', { type: 'checkbox' }); dueSoonChk.checked = settings.dueSoonEnabled;
    var densitySel = el('select', {}, ['compact', 'normal', 'large'].map(function (d) {
      var o = el('option', { value: d, text: d });
      if (settings.density === d) o.setAttribute('selected', '');
      return o;
    }));
    var settingsBox = el('div', { class: 'ppx-settings' }, [
      el('label', {}, [badgeChk, el('span', { text: 'Badge on pages that are sent to press' })]),
      el('label', {}, [watermarkChk, el('span', { text: 'Watermark on pages that are sent to press' })]),
      el('label', {}, [el('span', { text: 'Watermark text:' })]),
      watermarkInput,
      el('label', {}, [el('span', { text: 'Press status names:' })]),
      pressInput,
      el('label', {}, [accentChk, el('span', { text: 'Status color accent on page tiles' })]),
      el('label', {}, [overdueChk, el('span', { text: 'Highlight late pages (past hard deadline)' })]),
      el('label', {}, [dueSoonChk, el('span', { text: 'Highlight approaching pages (past soft deadline)' })]),
      el('label', {}, [el('span', { text: 'Grid density:' }), densitySel]),
    ]);
    function persistSettings() {
      settings.pressStatusNames = pressInput.value.split(',').map(function (s) { return s.trim(); }).filter(Boolean);
      settings.badgeEnabled = badgeChk.checked;
      settings.watermarkEnabled = watermarkChk.checked;
      settings.watermarkText = watermarkInput.value.trim();
      settings.accentsEnabled = accentChk.checked;
      settings.overdueEnabled = overdueChk.checked;
      settings.dueSoonEnabled = dueSoonChk.checked;
      settings.density = densitySel.value;
      saveSettings(settings);
      stylingRefresh();
    }
    [pressInput, badgeChk, watermarkChk, watermarkInput, accentChk, overdueChk, dueSoonChk, densitySel].forEach(function (input) {
      input.addEventListener('change', persistSettings);
    });
    var gearBtn = el('button', { class: 'ppx-gear', title: 'Styling settings', text: '⚙' });
    gearBtn.addEventListener('click', function () { settingsBox.classList.toggle('ppx-open'); });

    var dialog = el('div', { class: 'ppx-dialog' }, [
      el('h2', { text: 'Export PDF' }),
      el('div', { class: 'ppx-body' }, [
        ctxLine,
        el('fieldset', {}, [
          el('legend', { text: 'Pages' }),
          el('label', {}, [scopeIssue, el('span', { text: 'Entire issue' })]),
          el('label', {}, [scopeRange, el('span', { text: 'Page range:' }), rangeInput]),
        ]),
        el('fieldset', {}, [el('legend', { text: 'Only statuses' }), statusBox]),
        el('fieldset', {}, [el('legend', { text: 'Edition' }), editionSelect]),
        renditionNote,
        errLine,
        progressWrap,
        settingsBox,
      ]),
      el('div', { class: 'ppx-actions' }, [
        gearBtn,
        el('div', { class: 'ppx-right' }, [cancelBtn, exportBtn]),
      ]),
    ]);
    var overlay = el('div', { class: 'ppx-dialog-overlay' }, [dialog]);
    document.body.appendChild(overlay);

    function close() {
      state.cancelled = true;
      if (overlay.parentNode) overlay.parentNode.removeChild(overlay);
    }
    cancelBtn.addEventListener('click', function () {
      if (state.exporting) { state.cancelled = true; return; }
      close();
    });
    overlay.addEventListener('click', function (ev) { if (ev.target === overlay && !state.exporting) close(); });

    function showError(msg) { errLine.textContent = msg || ''; }

    function selectedStates() {
      return [].slice.call(statusBox.querySelectorAll('input:checked')).map(function (c) { return c.getAttribute('data-state-id'); });
    }

    function renderModel(model) {
      state.model = model;
      // GetPagesInfo omits brand/issue names; use the ones from loadIssueMeta
      // once available (survives edition reloads).
      if (state.meta) {
        if (state.meta.brandName) model.brandName = state.meta.brandName;
        if (state.meta.issueName) model.issueName = state.meta.issueName;
      }
      var withPdf = model.pages.filter(function (p) { return p.outputAvailable; }).length;
      ctxLine.textContent = (model.brandName || 'Brand') + ' / ' + (model.issueName || ('issue ' + model.issueId)) +
        ' — ' + model.pages.length + ' pages, ' + Object.keys(model.layouts).length + ' layouts';
      renditionNote.textContent = withPdf === model.pages.length
        ? 'All pages have stored print PDFs.'
        : withPdf + ' of ' + model.pages.length + ' pages have print PDFs; JPG previews will be used for the rest.';
      statusBox.textContent = '';
      model.states.forEach(function (st) {
        var chk = el('input', { type: 'checkbox', 'data-state-id': st.id });
        chk.checked = true;
        statusBox.appendChild(el('label', {}, [
          chk,
          el('span', { class: 'ppx-state-dot', style: 'background:' + (st.color || '#ccc') }),
          el('span', { text: st.name || ('status ' + st.id) }),
        ]));
      });
      exportBtn.disabled = false;
    }

    function loadFor(editionId) {
      exportBtn.disabled = true;
      showError('');
      return loadIssueModel(filter.issueId, editionId).then(renderModel).catch(function (e) {
        ctxLine.textContent = 'Failed to load issue.';
        showError(e.message);
      });
    }

    // initial load: current edition + issue meta (brand/issue names, editions)
    loadFor(filter.editionId);
    loadIssueMeta(filter.brandId, filter.issueId).then(function (meta) {
      state.meta = meta;
      state.editions = meta.editions;
      // Names are absent from GetPagesInfo; fold them into the model so the
      // context line and download filename read properly.
      if (state.model) {
        if (meta.brandName) state.model.brandName = meta.brandName;
        if (meta.issueName) state.model.issueName = meta.issueName;
        renderModel(state.model);
      }
      editionSelect.textContent = '';
      if (!meta.editions.length) {
        editionSelect.appendChild(el('option', { value: filter.editionId || '', text: 'Current edition' }));
        return;
      }
      meta.editions.forEach(function (ed) {
        var o = el('option', { value: ed.id, text: ed.name });
        if (String(ed.id) === String(filter.editionId)) o.setAttribute('selected', '');
        editionSelect.appendChild(o);
      });
    });
    editionSelect.addEventListener('change', function () { loadFor(editionSelect.value); });

    exportBtn.addEventListener('click', function () {
      var model = state.model;
      if (!model || state.exporting) return;
      showError('');

      var pages = model.pages.slice();
      var suffixes = [];
      try {
        if (scopeRange.checked) {
          if (!rangeInput.value.trim()) throw new Error('Enter a page range, e.g. 1-5, 9');
          pages = filterPagesByRange(pages, rangeInput.value);
          suffixes.push('pages ' + rangeInput.value.replace(/\s+/g, ''));
        }
        var states = selectedStates();
        if (states.length && states.length < model.states.length) {
          pages = pages.filter(function (p) {
            var lay = model.layouts[p.layoutId];
            return lay && states.indexOf(lay.stateId) >= 0;
          });
          suffixes.push(model.states.filter(function (s) { return states.indexOf(s.id) >= 0; })
            .map(function (s) { return s.name; }).join('+'));
        }
        if (!pages.length) throw new Error('No pages match the chosen scope and filters.');
      } catch (e) { showError(e.message); return; }

      var edName = '';
      if (state.editions.length > 1) {
        var sel = state.editions.filter(function (ed) { return ed.id === editionSelect.value; })[0];
        if (sel) { edName = sel.name; suffixes.push(sel.name); }
      }

      var source = createRenditionSource(loadSettings(), model.issueId, editionSelect.value || model.editionId);
      var layoutIds = [];
      pages.forEach(function (p) { if (layoutIds.indexOf(p.layoutId) < 0) layoutIds.push(p.layoutId); });

      state.exporting = true;
      state.cancelled = false;
      exportBtn.disabled = true;
      cancelBtn.textContent = 'Cancel';
      progressWrap.style.display = 'block';
      progressText.textContent = 'Fetching page list…';

      source.prime(layoutIds).then(function () {
        return exportPdf(pages, source, {
          onProgress: function (done, total, page) {
            progressFill.style.width = Math.round(done / total * 100) + '%';
            progressText.textContent = 'Page ' + page.pageNumber + ' — ' + done + ' of ' + total;
          },
          isCancelled: function () { return state.cancelled; },
        });
      }).then(function (result) {
        var filename = buildFilename(model, suffixes);
        downloadBlob(result.bytes, filename);
        var msg = 'Exported ' + result.pageCount + ' pages to "' + filename + '"';
        if (result.skipped.length) {
          msg += ' — ' + result.skipped.length + ' skipped (no rendition): ' +
            result.skipped.map(function (s) { return s.page.pageNumber; }).join(', ');
        }
        notify(msg, result.skipped.length ? 'default' : 'success');
        close();
      }).catch(function (e) {
        if (e && e.message === '__cancelled__') {
          progressText.textContent = 'Cancelled.';
        } else {
          showError(e.message);
        }
      }).then(function () {
        state.exporting = false;
        exportBtn.disabled = false;
        cancelBtn.textContent = 'Close';
      });
    });
  }

// ─── Styling engine ────────────────────────────────────────────────────────
// Decorates the Publication Overview page tiles. Deliberately defensive:
// WoodWing does not document the PO DOM, so every selector lives in the
// SELECTORS map below (patch here after a Studio upgrade), every pass is
// wrapped in try/catch, and after 3 consecutive failures the engine turns
// itself off for the session without touching the export functionality.
// All decoration is keyed off ppx-* classes so removal fully reverts it.

var SELECTORS = {
  tile: 'po-page-component',
  footer: '.page-footer-wrapper',
  pageNumber: '.page-number span',
  grid: 'po-spread-view',
};

// ═══════════════════════════════════════════════════════════════════════
//  WATERMARK STYLE — edit this block freely to restyle the overlay.
//
//  Injected per press-status page tile (pointer-events pass through):
//     <div class="ppx-watermark">
//       <span class="ppx-watermark-text">SENT TO PRESS</span>
//     </div>
//  .ppx-watermark is the full-cover container over the thumbnail;
//  .ppx-watermark-text is the label (text comes from the watermarkText
//  setting). Keep the container's `position/inset/pointer-events` unless
//  you know you want otherwise; everything else is yours.
// ═══════════════════════════════════════════════════════════════════════
var WATERMARK_CSS =
  '.ppx-watermark{position:absolute;inset:0;z-index:6;display:flex;' +
  'align-items:center;justify-content:center;overflow:hidden;pointer-events:none}' +
  '.ppx-watermark-text{transform: rotate(-32deg);font: 800 20px / 1 sans-serif;letter-spacing: .12em;text-align: center;text-transform: uppercase;color: rgba(192, 57, 43, .8);border: 3px solid rgba(192, 57, 43, .8);padding: 11px 16px;border-radius: 4px;background-color: rgba(226, 226, 226, .6);}';

// ═══════════════════════════════════════════════════════════════════════
//  DEADLINE STYLE — edit this block freely to restyle deadline highlights.
//
//  Two mutually-exclusive classes are toggled on the page tile
//  (<po-page-component>), only on non-press pages:
//     .ppx-overdue   → hard deadline (Deadline) has passed        → "late"
//     .ppx-due-soon  → soft deadline (DeadlineSoft) passed, hard  → "approaching"
//                       deadline not yet passed
//  "Late" wins if both apply. Defaults: red pulse for late, amber for
//  approaching. Everything here is yours to change.
// ═══════════════════════════════════════════════════════════════════════
var DEADLINE_CSS =
  'po-page-component.ppx-overdue{border-top: 4px solid #f7625e;border-left: 4px solid #f7625e;box-sizing: border-box;animation:ppx-pulse 1.6s ease-in-out infinite}' +
  '@keyframes ppx-pulse{0%,100%{border-color: rgb(254 127 45 / 90%);}50%{border-color: rgb(254 127 45 / 30%);}}' +
  'po-page-component.ppx-due-soon{outline:2px solid #e0a800;outline-offset:-2px}';

var STYLING_CSS =
  'po-page-component.ppx-tile{position:relative}' +
  '.ppx-badge{position:absolute;top:8px;right:8px;z-index:5;background:rgba(46,158,60,.92);color:#fff;' +
  'font-size:10px;font-weight:700;letter-spacing:.08em;padding:3px 8px;border-radius:3px;pointer-events:none;' +
  'box-shadow:0 1px 4px rgba(0,0,0,.3)}' +
  '.ppx-accent-bar{position:absolute;left:0;right:0;bottom:0;height:4px;z-index:4;pointer-events:none}' +
  '[data-ppx-density="compact"] .spread-view{zoom:0.7}' +
  '[data-ppx-density="large"] .spread-view{zoom:1.35}' +
  DEADLINE_CSS +
  WATERMARK_CSS;

var styling = (function () {
  var observer = null;
  var model = null;
  var failures = 0;
  var disabled = false;
  var scheduled = false;

  function injectCss() {
    if (!document.getElementById('ppx-styling-styles')) {
      var st = document.createElement('style');
      st.id = 'ppx-styling-styles';
      st.textContent = STYLING_CSS;
      document.head.appendChild(st);
    }
  }

  function pageByNumber(num) {
    if (!model) return null;
    for (var i = 0; i < model.pages.length; i++) {
      if (model.pages[i].pageNumber === String(num)) return model.pages[i];
    }
    return null;
  }

  function isPressState(settings, stateName) {
    var name = String(stateName || '').toLowerCase();
    return settings.pressStatusNames.some(function (s) { return s.toLowerCase() === name; });
  }

  function decorateTile(tile, settings) {
    var numEl = tile.querySelector(SELECTORS.pageNumber);
    if (!numEl) return;
    var page = pageByNumber(numEl.textContent.trim());
    var layout = page && model.layouts[page.layoutId];

    tile.classList.add('ppx-tile');

    // badge
    var badge = tile.querySelector(':scope > .ppx-badge');
    var wantBadge = settings.badgeEnabled && layout && isPressState(settings, layout.stateName);
    if (wantBadge && !badge) {
      badge = document.createElement('div');
      badge.className = 'ppx-badge';
      tile.appendChild(badge);
    }
    if (badge) {
      if (wantBadge) badge.textContent = settings.badgeLabel || 'PRESS';
      else badge.remove();
    }

    // diagonal watermark (same press-status trigger as the badge)
    var watermark = tile.querySelector(':scope > .ppx-watermark');
    var wantWatermark = settings.watermarkEnabled && layout && isPressState(settings, layout.stateName);
    if (wantWatermark && !watermark) {
      watermark = document.createElement('div');
      watermark.className = 'ppx-watermark';
      watermark.appendChild(document.createElement('span')).className = 'ppx-watermark-text';
      tile.appendChild(watermark);
    }
    if (watermark) {
      if (wantWatermark) {
        watermark.firstChild.textContent = settings.watermarkText || 'SENT TO PRESS';
      } else {
        watermark.remove();
      }
    }

    // status accent
    var bar = tile.querySelector(':scope > .ppx-accent-bar');
    var wantBar = settings.accentsEnabled && layout && layout.stateColor;
    if (wantBar && !bar) {
      bar = document.createElement('div');
      bar.className = 'ppx-accent-bar';
      tile.appendChild(bar);
    }
    if (bar) {
      if (wantBar) bar.style.background = layout.stateColor;
      else bar.remove();
    }

    // deadline highlights (non-press pages only): hard deadline passed =
    // "late" (wins); else soft deadline passed = "approaching".
    var late = false, dueSoon = false;
    if (layout && !isPressState(settings, layout.stateName)) {
      var now = Date.now();
      var hard = layout.deadline ? new Date(layout.deadline).getTime() : NaN;
      var soft = layout.deadlineSoft ? new Date(layout.deadlineSoft).getTime() : NaN;
      if (settings.overdueEnabled && !isNaN(hard) && hard < now) late = true;
      else if (settings.dueSoonEnabled && !isNaN(soft) && soft < now) dueSoon = true;
    }
    tile.classList.toggle('ppx-overdue', late);
    tile.classList.toggle('ppx-due-soon', dueSoon);
  }

  function pass() {
    scheduled = false;
    if (disabled || !model) return;
    try {
      var settings = loadSettings();
      var tiles = document.querySelectorAll(SELECTORS.tile);
      for (var i = 0; i < tiles.length; i++) decorateTile(tiles[i], settings);
      var grid = document.querySelector(SELECTORS.grid);
      if (grid) {
        if (settings.density && settings.density !== 'normal') grid.setAttribute('data-ppx-density', settings.density);
        else grid.removeAttribute('data-ppx-density');
      }
      failures = 0;
    } catch (e) {
      failures++;
      console.warn(TAG + ' styling pass failed (' + failures + '/3): ' + e.message);
      if (failures >= 3) stop('repeated DOM errors — Studio update? See docs/discovery-notes.md SELECTORS.');
    }
  }

  function schedule() {
    if (scheduled || disabled) return;
    scheduled = true;
    requestAnimationFrame(function () { setTimeout(pass, 100); });
  }

  function start(newModel) {
    model = newModel;
    if (disabled) return;
    injectCss();
    if (!observer) {
      observer = new MutationObserver(schedule);
      observer.observe(document.body, { childList: true, subtree: true });
    }
    schedule();
  }

  function stop(reason) {
    disabled = true;
    if (observer) { observer.disconnect(); observer = null; }
    try {
      document.querySelectorAll('.ppx-badge,.ppx-accent-bar,.ppx-watermark').forEach(function (n) { n.remove(); });
      document.querySelectorAll('.ppx-overdue,.ppx-due-soon').forEach(function (n) {
        n.classList.remove('ppx-overdue'); n.classList.remove('ppx-due-soon');
      });
      var grid = document.querySelector(SELECTORS.grid);
      if (grid) grid.removeAttribute('data-ppx-density');
    } catch (e) { /* best effort */ }
    console.warn(TAG + ' styling disabled: ' + (reason || 'stopped'));
  }

  return {
    start: start,
    stop: stop,
    refresh: schedule,
    setModel: function (m) { model = m; schedule(); },
    _state: function () { return { disabled: disabled, failures: failures, hasModel: !!model }; },
  };
})();

function stylingRefresh() { styling.refresh(); }

  // ─── Settings ──────────────────────────────────────────────────────────────
  // localStorage for v1. The load/save pair is the seam for a later
  // SaveUserSettings/GetUserSettings-backed store (settings that roam with
  // the Studio user) — keep all access going through these two functions.
  var SETTINGS_KEY = 'pubOverviewPlugin.settings.v1';

  function loadSettings() {
    var stored = {};
    try { stored = JSON.parse(localStorage.getItem(SETTINGS_KEY)) || {}; } catch (e) { /* fresh */ }
    var merged = {};
    Object.keys(DEFAULT_SETTINGS).forEach(function (k) {
      merged[k] = (k in stored) ? stored[k] : DEFAULT_SETTINGS[k];
    });
    return merged;
  }

  function saveSettings(settings) {
    try { localStorage.setItem(SETTINGS_KEY, JSON.stringify(settings)); } catch (e) {
      console.warn(TAG + ' could not persist settings: ' + e.message);
    }
  }

  // ─── Registration & lifecycle ──────────────────────────────────────────────
  try {
    if (PoUiSdk.hasActions()) PoUiSdk.createAction(); // separator below other plug-ins
    PoUiSdk.createAction({
      label: 'Export PDF…',
      click: function () {
        try { openExportDialog(); }
        catch (e) { console.error(TAG + ' export dialog failed:', e); notify('Export failed to open: ' + e.message, 'error'); }
      },
    });
  } catch (e) {
    console.error(TAG + ' could not register menu action:', e);
  }

  // Styling lifecycle: load the issue model for the current filter and keep
  // it fresh when the user navigates to another issue/edition (the iframe
  // hash changes) — plus a slow safety refresh for state changes made by
  // other users.
  var lastModelKey = '';
  function refreshStylingModel() {
    try {
      var f = currentFilter();
      if (!f.issueId) return;
      var key = f.issueId + '|' + (f.editionId || '');
      if (key === lastModelKey) { styling.refresh(); return; }
      lastModelKey = key;
      loadIssueModel(f.issueId, f.editionId)
        .then(loadDeadlines)
        .then(function (model) { styling.start(model); })
        .catch(function (e) {
          lastModelKey = ''; // retry on next tick
          console.warn(TAG + ' styling model load failed: ' + e.message);
        });
    } catch (e) {
      console.warn(TAG + ' styling refresh failed: ' + e.message);
    }
  }

  window.addEventListener('hashchange', refreshStylingModel);
  setInterval(function () { lastModelKey = ''; refreshStylingModel(); }, 60000);
  refreshStylingModel();

  // Console diagnostics: window.__pubPdfDebug
  window.__pubPdfDebug = {
    version: VERSION,
    selectors: SELECTORS,
    settings: loadSettings,
    saveSettings: saveSettings,
    styling: styling,
    loadIssueModel: loadIssueModel,
    currentFilter: currentFilter,
    openExportDialog: openExportDialog,
  };

  console.info(TAG + ' v' + VERSION + ' loaded');

})();
